package test.rice.concisegen;

import main.rice.concisegen.ConciseSetGenerator;
import main.rice.obj.PyIntObj;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import org.junit.jupiter.api.Test;

import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertEquals;

class ConciseSetGeneratorAgentTest {

    private TestCase tc(int value) {
        return new TestCase(List.of(new PyIntObj(value)));
    }

    @Test
    void setCoverFindsSingleBestTestWhenItCoversEverything() {
        List<TestCase> allCases = Arrays.asList(tc(1), tc(2), tc(3));
        List<Set<Integer>> caseToFiles = Arrays.asList(
            Set.of(0, 1, 2),
            Set.of(0),
            Set.of(1, 2)
        );
        TestResults results = new TestResults(allCases, caseToFiles, Set.of(0, 1, 2));

        assertEquals(List.of(tc(1)), ConciseSetGenerator.setCover(results));
    }

    @Test
    void setCoverUsesGreedyCombinationToCoverRemainingFiles() {
        List<TestCase> allCases = Arrays.asList(tc(10), tc(20), tc(30), tc(40));
        List<Set<Integer>> caseToFiles = Arrays.asList(
            Set.of(0, 1),
            Set.of(2),
            Set.of(1, 2, 3),
            Set.of(3)
        );
        TestResults results = new TestResults(allCases, caseToFiles, Set.of(0, 1, 2, 3));

        assertEquals(List.of(tc(30), tc(10)), ConciseSetGenerator.setCover(results));
    }

    @Test
    void setCoverReturnsEmptyWhenNothingIsWrongOrCoverIsImpossible() {
        List<TestCase> allCases = Arrays.asList(tc(5), tc(6));
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(),
            Set.of(1)
        );

        TestResults noFailures = new TestResults(allCases, caseToFiles, Set.of());
        assertEquals(List.of(), ConciseSetGenerator.setCover(noFailures));

        TestResults impossible = new TestResults(allCases, caseToFiles, Set.of(0, 2));
        assertEquals(List.of(), ConciseSetGenerator.setCover(impossible));
    }
}

package test.rice.node;

import main.rice.node.PyBoolNode;
import main.rice.node.PyFloatNode;
import main.rice.node.PyIntNode;
import main.rice.obj.APyObj;
import main.rice.obj.PyBoolObj;
import main.rice.obj.PyFloatObj;
import main.rice.obj.PyIntObj;
import org.junit.jupiter.api.Test;

import java.util.Arrays;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import static org.junit.jupiter.api.Assertions.*;

class PrimitivePyNodeAgentTest {

    @Test
    void boolNodeIsLeafAndGeneratesExhaustiveValues() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(0, 1, 0));

        assertNull(node.getLeftChild());
        assertNull(node.getRightChild());
        assertEquals(
            Arrays.asList(new PyBoolObj(false), new PyBoolObj(true), new PyBoolObj(false)),
            node.genExVals()
        );
    }

    @Test
    void intNodeGeneratesExhaustiveAndRandomValuesFromDomain() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(-2, 0, 5));
        node.setRanDomain(Arrays.asList(7, 9));

        assertEquals(
            Arrays.asList(new PyIntObj(-2), new PyIntObj(0), new PyIntObj(5)),
            node.genExVals()
        );

        Set<Integer> allowed = Set.of(7, 9);
        for (int i = 0; i < 40; i++) {
            APyObj value = node.genRandVal();
            assertTrue(value instanceof PyIntObj);
            assertTrue(allowed.contains(((PyIntObj) value).getValue()));
        }
    }

    @Test
    void floatNodeGeneratesExhaustiveAndRandomValuesFromDomain() {
        PyFloatNode node = new PyFloatNode();
        node.setExDomain(Arrays.asList(-1.5, 0.0, 2.25));
        node.setRanDomain(Arrays.asList(3.5, 4.75));

        List<APyObj> expected = Arrays.asList(
            new PyFloatObj(-1.5),
            new PyFloatObj(0.0),
            new PyFloatObj(2.25)
        );
        assertEquals(expected, node.genExVals());

        Set<Double> allowed = Set.of(3.5, 4.75);
        for (int i = 0; i < 40; i++) {
            APyObj value = node.genRandVal();
            assertTrue(value instanceof PyFloatObj);
            assertTrue(allowed.contains(((PyFloatObj) value).getValue()));
        }
    }

    @Test
    void nullOrEmptyRandomDomainsReturnNull() {
        PyBoolNode boolNode = new PyBoolNode();
        PyIntNode intNode = new PyIntNode();
        PyFloatNode floatNode = new PyFloatNode();

        assertNull(boolNode.genRandVal());

        intNode.setRanDomain(List.of());
        floatNode.setRanDomain(List.of());

        assertNull(intNode.genRandVal());
        assertNull(floatNode.genRandVal());
    }

    @Test
    void boolRandomValuesStayInBooleanImage() {
        PyBoolNode node = new PyBoolNode();
        node.setRanDomain(Arrays.asList(0, 1));

        Set<Boolean> produced = Arrays.stream(new int[50])
            .mapToObj(ignored -> ((PyBoolObj) node.genRandVal()).getValue())
            .collect(Collectors.toSet());

        assertTrue(produced.contains(false) || produced.contains(true));
        assertTrue(produced.stream().allMatch(value -> value.equals(Boolean.TRUE) || value.equals(Boolean.FALSE)));
    }
}

package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates concise test suites using greedy set cover.
 */
public final class ConciseSetGenerator {

    private ConciseSetGenerator() {
    }

    /**
     * Selects a concise subset of test cases whose caught files cover every file in the
     * wrong set. This method does not mutate the input results object.
     *
     * @param results the full test results
     * @return a greedy set cover of the failing files
     */
    public static List<TestCase> setCover(TestResults results) {
        List<TestCase> conciseSet = new ArrayList<>();
        if (results == null) {
            return conciseSet;
        }

        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        if (caseToFiles == null) {
            return conciseSet;
        }

        Set<Integer> remaining = new HashSet<>();
        if (results.getWrongSet() != null) {
            remaining.addAll(results.getWrongSet());
        }

        while (!remaining.isEmpty()) {
            int bestIndex = -1;
            int bestCoverage = 0;

            for (int i = 0; i < caseToFiles.size(); i++) {
                Set<Integer> caught = caseToFiles.get(i);
                if (caught == null) {
                    continue;
                }

                int coverage = 0;
                for (Integer fileIndex : caught) {
                    if (remaining.contains(fileIndex)) {
                        coverage++;
                    }
                }

                if (coverage > bestCoverage) {
                    bestCoverage = coverage;
                    bestIndex = i;
                }
            }

            if (bestIndex < 0) {
                break;
            }

            TestCase chosen = results.getTestCase(bestIndex);
            if (chosen != null) {
                conciseSet.add(chosen);
            }
            remaining.removeAll(caseToFiles.get(bestIndex));
        }

        return conciseSet;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyFloatObj;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ThreadLocalRandom;

/**
 * A leaf node for generating Python float objects.
 */
public class PyFloatNode extends APyNode<Double> {

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public List<APyObj> genExVals() {
        List<APyObj> values = new ArrayList<>();
        List<Double> domain = this.getExDomain();
        if (domain == null) {
            return values;
        }

        for (Double entry : domain) {
            values.add(new PyFloatObj(entry));
        }
        return values;
    }

    @Override
    public APyObj genRandVal() {
        List<Double> domain = this.getRanDomain();
        if ((domain == null) || domain.isEmpty()) {
            return null;
        }

        int index = ThreadLocalRandom.current().nextInt(domain.size());
        return new PyFloatObj(domain.get(index));
    }
}

