package main.rice.node;

import main.rice.obj.APyObj;

import java.util.List;

/**
 * An abstract generator node for Python-object domains.
 *
 * @param <D> the Java type used in this node's domains
 */
public abstract class APyNode<D> {

    /**
     * The exhaustive domain for this node.
     */
    private List<D> exDomain;

    /**
     * The random domain for this node.
     */
    private List<D> ranDomain;

    /**
     * Returns this node's exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<D> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets this node's exhaustive domain.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<D> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns this node's random domain.
     *
     * @return the random domain
     */
    public List<D> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets this node's random domain.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<D> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the left child of this node, or null for leaves.
     *
     * @return the left child
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child of this node, or null for leaves.
     *
     * @return the right child
     */
    public abstract APyNode<?> getRightChild();

    /**
     * Generates all values in the exhaustive domain.
     *
     * @return the generated exhaustive values
     */
    public abstract List<APyObj> genExVals();

    /**
     * Generates a random value from the random domain.
     *
     * @return the generated random value
     */
    public abstract APyObj genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyBoolObj;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ThreadLocalRandom;

/**
 * A leaf node for generating Python boolean objects.
 */
public class PyBoolNode extends APyNode<Integer> {

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public List<APyObj> genExVals() {
        List<APyObj> values = new ArrayList<>();
        List<Integer> domain = this.getExDomain();
        if (domain == null) {
            return values;
        }

        for (Integer entry : domain) {
            values.add(new PyBoolObj(entry != 0));
        }
        return values;
    }

    @Override
    public APyObj genRandVal() {
        List<Integer> domain = this.getRanDomain();
        if ((domain == null) || domain.isEmpty()) {
            return null;
        }

        int index = ThreadLocalRandom.current().nextInt(domain.size());
        return new PyBoolObj(domain.get(index) != 0);
    }
}

