+package test.rice.node;
+
+import main.rice.node.PyBoolNode;
+import main.rice.node.PyFloatNode;
+import main.rice.node.PyIntNode;
+import main.rice.obj.APyObj;
+import main.rice.obj.PyBoolObj;
+import main.rice.obj.PyFloatObj;
+import main.rice.obj.PyIntObj;
+import org.junit.jupiter.api.Test;
+
+import java.util.Arrays;
+import java.util.List;
+import java.util.Set;
+import java.util.stream.Collectors;
+
+import static org.junit.jupiter.api.Assertions.*;
+
+class PrimitivePyNodeAgentTest {
+
+    @Test
+    void boolNodeIsLeafAndGeneratesExhaustiveValues() {
+        PyBoolNode node = new PyBoolNode();
+        node.setExDomain(Arrays.asList(0, 1, 0));
+
+        assertNull(node.getLeftChild());
+        assertNull(node.getRightChild());
+        assertEquals(
+            Arrays.asList(new PyBoolObj(false), new PyBoolObj(true), new PyBoolObj(false)),
+            node.genExVals()
+        );
+    }
+
+    @Test
+    void intNodeGeneratesExhaustiveAndRandomValuesFromDomain() {
+        PyIntNode node = new PyIntNode();
+        node.setExDomain(Arrays.asList(-2, 0, 5));
+        node.setRanDomain(Arrays.asList(7, 9));
+
+        assertEquals(
+            Arrays.asList(new PyIntObj(-2), new PyIntObj(0), new PyIntObj(5)),
+            node.genExVals()
+        );
+
+        Set<Integer> allowed = Set.of(7, 9);
+        for (int i = 0; i < 40; i++) {
+            APyObj value = node.genRandVal();
+            assertTrue(value instanceof PyIntObj);
+            assertTrue(allowed.contains(((PyIntObj) value).getValue()));
+        }
+    }
+
+    @Test
+    void floatNodeGeneratesExhaustiveAndRandomValuesFromDomain() {
+        PyFloatNode node = new PyFloatNode();
+        node.setExDomain(Arrays.asList(-1.5, 0.0, 2.25));
+        node.setRanDomain(Arrays.asList(3.5, 4.75));
+
+        List<APyObj> expected = Arrays.asList(
+            new PyFloatObj(-1.5),
+            new PyFloatObj(0.0),
+            new PyFloatObj(2.25)
+        );
+        assertEquals(expected, node.genExVals());
+
+        Set<Double> allowed = Set.of(3.5, 4.75);
+        for (int i = 0; i < 40; i++) {
+            APyObj value = node.genRandVal();
+            assertTrue(value instanceof PyFloatObj);
+            assertTrue(allowed.contains(((PyFloatObj) value).getValue()));
+        }
+    }
+
+    @Test
+    void nullOrEmptyRandomDomainsReturnNull() {
+        PyBoolNode boolNode = new PyBoolNode();
+        PyIntNode intNode = new PyIntNode();
+        PyFloatNode floatNode = new PyFloatNode();
+
+        assertNull(boolNode.genRandVal());
+
+        intNode.setRanDomain(List.of());
+        floatNode.setRanDomain(List.of());
+
+        assertNull(intNode.genRandVal());
+        assertNull(floatNode.genRandVal());
+    }
+
+    @Test
+    void boolRandomValuesStayInBooleanImage() {
+        PyBoolNode node = new PyBoolNode();
+        node.setRanDomain(Arrays.asList(0, 1));
+
+        Set<Boolean> produced = Arrays.stream(new int[50])
+            .mapToObj(ignored -> ((PyBoolObj) node.genRandVal()).getValue())
+            .collect(Collectors.toSet());
+
+        assertTrue(produced.contains(false) || produced.contains(true));
+        assertTrue(produced.stream().allMatch(value -> value.equals(Boolean.TRUE) || value.equals(Boolean.FALSE)));
+    }
